solution_code:
#include <iostream>

int main() {
    int n;
    std::cin >> n;

    if (n > 0)      goto is_positive;
    else if (n < 0) goto is_negative;
    else            goto is_zero;

is_positive:
    std::cout << "positive\n";
    goto end;
is_negative:
    std::cout << "negative\n";
    goto end;
is_zero:
    std::cout << "zero\n";
end:
    return 0;
}

