solution_code:
#include <iostream>

int main() {
    int n;
    std::cin >> n;
    int sum = 0;
    int i = 0;
loop:
    if (i < n) {
        int val;
        std::cin >> val;
        sum = sum + val;
        ++i;
        goto loop;
    }
    std::cout << "Sum: " << sum << "\n";
    return 0;
}
